void* malloc(size_t size)
{
 // Ask the system for more bytes by extending the heap space.
 // sbrk returns -1 on failure
 void *p = sbrk(size);
 if(p == (void *) -1) return NULL; // No space left
 return p;
}
 void free() {/* Do nothing */}
